 1→import PropTypes from 'prop-types';
 2→import {useCallback, useEffect, useRef} from 'react';
 3→import {getQueryParam} from 'src/utils/url';
 4→import {
 5→  fireEcommerceEvent,
 6→  fireListingsImpressionsEvents,
 7→  getEcommerceEventPayload,
 8→  getItemEcomerceData,
 9→  getListingImpressionsName
10→} from './utils/productsAnalytics';
11→
12→export default function useProductAnalyticsEvents({
13→  categoryId,
14→  categoryTree,
15→  fireProductImpressionsOnLoad = true,
16→  hits,
17→  isCustomPage = false,
18→  isSearchResults = false
19→}) {
20→  const hasFiredEvent = useRef(false);
21→
22→  useEffect(() => {
23→    if (
24→      !hasFiredEvent.current &&
25→      hits.length > 0 &&
26→      fireProductImpressionsOnLoad
27→    ) {
28→      const items = hits.map((hit, index) =>
29→        getItemEcomerceData(hit, index + 1)
30→      );
31→
32→      fireEcommerceEvent(
33→        getEcommerceEventPayload(items, categoryId, categoryTree),
34→        'view_item_list',
35→        {search_term: getQueryParam('keyword')}
36→      );
37→      fireListingsImpressionsEvents(hits);
38→      hasFiredEvent.current = true;
39→    }
40→  }, [hits, fireProductImpressionsOnLoad, categoryId, categoryTree]);
41→
42→  const fireSelectProductEvent = useCallback(
43→    (hit, index) => {
44→      const item = getItemEcomerceData(hit, index, {
45→        item_list_name: getListingImpressionsName({
46→          isCustomPage,
47→          isSearchResults
48→        })
49→      });
50→      const ecommerceEventPayload = getEcommerceEventPayload(
51→        [item],
52→        categoryId,
53→        categoryTree
54→      );
55→      fireEcommerceEvent(ecommerceEventPayload, 'select_item', {
56→        search_term: getQueryParam('keyword')
57→      });
58→    },
59→    [categoryId, categoryTree, isCustomPage, isSearchResults]
60→  );
61→
62→  return {fireSelectProductEvent};
63→}
64→
65→useProductAnalyticsEvents.propTypes = {
66→  categoryId: PropTypes.number.isRequired,
67→  categoryTree: PropTypes.string.isRequired,
68→  fireProductImpressionsOnLoad: PropTypes.bool,
69→  hits: PropTypes.array.isRequired,
70→  isCustomPage: PropTypes.bool,
71→  isSearchResults: PropTypes.bool
72→};
