 1→import {getProductDataImageUrl, getProductDataUrl} from './data_utils';
 2→export function getCategoryName(hit, index) {
 3→  return hit.breadcrumbs?.[index]?.name?.toLowerCase()?.replace(/\s/g, '_');
 4→}
 5→
 6→export function fireEcommerceEvent(
 7→  ecommerceEventPayload,
 8→  eventName,
 9→  eventAttributes = {}
10→) {
11→  window.dataLayer.push({
12→    ecommerce: null
13→  });
14→  window.dataLayer.push({
15→    ecommerce: ecommerceEventPayload,
16→    event: eventName,
17→    ...eventAttributes
18→  });
19→}
20→
21→export function getProductLink(hit) {
22→  if (hit.target_url) {
23→    return hit.target_url;
24→  }
25→  return hit.breadcrumbs && hit.breadcrumbs[hit.breadcrumbs.length - 1]?.path;
26→}
27→
28→export function getProductImpressionsEventPayload(
29→  hit,
30→  index,
31→  additionalData = {}
32→) {
33→  return {
34→    brand: hit.manufacturer,
35→    category: hit?.breadcrumbs
36→      ?.map((cat) => cat.name)
37→      .splice(0, (hit?.breadcrumbs?.length ?? 0) - 1),
38→    id: hit.product_id,
39→    image: getProductDataImageUrl(hit.product_id),
40→    name: hit.name,
41→    position: index + 1,
42→    url: getProductDataUrl(getProductLink(hit)),
43→    ...additionalData
44→  };
45→}
46→
47→export function fireCardImpressionEvent(cardImpressionsPayload) {
48→  window.dataLayer.push({
49→    [`ci.catalog.listingsImpression`]: cardImpressionsPayload,
50→    event: `ci.catalog.listingImpression`
51→  });
52→}
53→
54→export function fireListingsImpressionsEvents(
55→  hits,
56→  isCustomPage,
57→  isSearchResults
58→) {
59→  hits.forEach((hit, index) => {
60→    const cardImpressionsPayload = getProductImpressionsEventPayload(
61→      hit,
62→      index,
63→      {
64→        listing: getListingImpressionsName({
65→          isCustomPage,
66→          isSearchResults
67→        })
68→      }
69→    );
70→    fireCardImpressionEvent(cardImpressionsPayload);
71→  });
72→}
73→
74→export function getItemEcomerceData(hit, index) {
75→  return {
76→    index,
77→    item_id: Number(hit.product_id)
78→  };
79→}
80→
81→export function getEcommerceEventPayload(items, categoryId, categoryTree) {
82→  return {
83→    item_list_id: categoryId,
84→    item_list_name: categoryTree,
85→    items
86→  };
87→}
88→
89→export function getListingImpressionsName({isCustom, isSearchResults}) {
90→  // TODO: Check if still support this as there's not class `is-Custom` in the codebase
91→  if (isCustom) {
92→    return 'Listing Custom';
93→  }
94→  if (isSearchResults) {
95→    return 'Search Results';
96→  }
97→  return 'Listing';
98→}
