  1→/// <reference types="jquery" />
  2→
  3→declare global {
  4→  interface Window {
  5→    dataLayer?: DataLayerEntry[];
  6→  }
  7→
  8→  const ProductCatalog: ProductCatalogNamespace;
  9→  const StyleBitz: StyleBitzNamespace;
 10→}
 11→
 12→export type DataLayerEntry =
 13→  | CatalogEvent
 14→  | EcommerceEvent
 15→  | EcommerceClearEvent
 16→  | VirtualPageviewEvent
 17→  | Record<string, unknown>;
 18→
 19→export interface CatalogEvent {
 20→  event: `ci.catalog.${string}`;
 21→  [key: `ci.catalog.${string}`]: unknown;
 22→}
 23→
 24→export interface EcommerceEvent {
 25→  event: EcommerceEventName;
 26→  ecommerce: EcommercePayload;
 27→  [key: string]: unknown;
 28→}
 29→
 30→export interface EcommerceClearEvent {
 31→  ecommerce: null;
 32→}
 33→
 34→export interface VirtualPageviewEvent {
 35→  event: 'VirtualPageview';
 36→  virtualPageURL: string;
 37→  virtualPageTitle: string;
 38→  virtualPagePath: string;
 39→}
 40→
 41→export type EcommerceEventName =
 42→  | 'view_item'
 43→  | 'view_item_list'
 44→  | 'select_item'
 45→  | 'add_to_cart'
 46→  | 'remove_from_cart'
 47→  | 'view_promotion'
 48→  | 'select_promotion'
 49→  | 'purchase';
 50→
 51→export interface EcommercePayload {
 52→  item_list_id?: number;
 53→  item_list_name?: string;
 54→  items?: EcommerceItem[];
 55→  promotion_id?: string;
 56→  promotion_name?: string;
