 10→export const CLICK_SECTION = 'pdp related items tabbed view';
 11→
 12→export const EVENT_TYPE = {
 13→  ARROW_CLICKED: 'ARROW_CLICKED',
 14→  ITEM_CLICKED: 'ITEM_CLICKED',
 15→  TAB_CHANGED: 'TAB_CHANGED',
 16→  VIEWED: 'VIEWED'
 17→};
 18→
 19→export const prepareTabbedViewEventData = ({
 20→  activeTab,
 21→  arrowDirection = null,
 22→  ecommerce = {},
 23→  eventType = EVENT_TYPE.VIEWED,
 24→  firstTabChange = false,
 25→  previousTab = null,
 26→  styleId = null
 27→}) => {
 28→  const sharedData = {
 29→    event: 'recommendation_click',
 30→    interaction_category: 'pdp_similar_products',
 31→    interaction_label: 'alternative_related_items_v2',
 32→    ...(ecommerce ? {ecommerce} : {})
 33→  };
 34→
 35→  switch (eventType) {
 36→    case EVENT_TYPE.ITEM_CLICKED:
 37→      return {
 38→        ...sharedData,
 39→        active_tab: activeTab,
 40→        interaction_action: CLICK_EVENT,
 41→        product_style_id: styleId
 42→      };
 43→    case EVENT_TYPE.TAB_CHANGED:
 44→      return {
 45→        ...sharedData,
 46→        active_tab: activeTab.toLowerCase(),
 47→        first_tab_click: firstTabChange,
 48→        interaction_action: 'tab change',
 49→        previous_tab: previousTab.toLowerCase()
 50→      };
 51→    case EVENT_TYPE.ARROW_CLICKED:
 52→      return {
 53→        ...sharedData,
 54→        interaction_action: `${arrowDirection} click`
 55→      };
 56→    case EVENT_TYPE.VIEWED:
 57→    default:
 58→      return {
 59→        ...sharedData,
 60→        event: 'recommendation_view'
 61→      };
 62→  }
 63→};
 64→
 65→export const fireTabbedViewEvent = (eventData) => {
 66→  window.dataLayer.push(prepareTabbedViewEventData(eventData));
 67→};
 68→
 69→export const fireTabbedViewEventWithCallback = ({callback, eventData}) => {
 70→  const data = prepareTabbedViewEventData(eventData);
 71→  window.dataLayer.push({
 72→    ...data,
 73→    eventCallback: callback,
 74→    eventTimeout: 1500
 75→  });
 76→};
