109→const TrendingCarousel = ({
110→  categoryId = CATEGORY_PROMOTIONAL_PRODUCTS,
111→  categoryName = '',
112→  onProductClick,
113→  title = 'Trending Products'
114→}) => {
115→  const breakpoint = useBreakpoint();
116→  const isMobile = breakpoint === 'sm';
117→  const {isLoading, products} = useTrendingProductsWrapper({categoryId});
118→
119→  const [isFirstSlide, setIsFirstSlide] = useState(true);
120→  const [isLastSlide, setIsLastSlide] = useState(false);
121→
122→  const getSlidesPerView = () => {
123→    if (isMobile) {
124→      return products.length >= 3 ? 1.6 : 'auto';
125→    }
126→    return products.length >= 5 ? 4 : 'auto';
127→  };
128→
129→  const slidesPerView = getSlidesPerView();
130→  const gap = isMobile ? 8 : 16;
131→
132→  const sliderRef = useRef(null);
133→  const instanceRef = useRef(null);
134→
135→  useEffect(() => {
136→    if (sliderRef.current && products.length > 0) {
137→      instanceRef.current = new KeenSlider(sliderRef.current, {
138→        created: () => {
139→          setIsFirstSlide(true);
140→          setIsLastSlide(false);
141→        },
142→        initial: 0,
143→        loop: true,
144→        mode: 'snap',
145→        slideChanged: () => {
146→          setIsFirstSlide(false);
147→          setIsLastSlide(false);
148→        },
149→        slidesPerView,
150→        spacing: gap
151→      });
152→    }
153→
154→    return () => {
155→      if (instanceRef.current) {
156→        instanceRef.current.destroy();
157→        instanceRef.current = null;
158→      }
159→    };
160→  }, [products.length, slidesPerView, gap, isMobile]);
161→
162→  const boundingBoxRef = useRef(null);
163→  const hasFiredViewEvent = useRef(false);
164→  useResizeObserver(boundingBoxRef, () => instanceRef?.current?.refresh());
165→
166→  useEffect(() => {
167→    if (
168→      !boundingBoxRef.current ||
169→      products.length === 0 ||
170→      hasFiredViewEvent.current
171→    ) {
172→      return;
173→    }
174→
175→    const observer = new IntersectionObserver(
176→      (entries) => {
177→        entries.forEach((entry) => {
178→          if (entry.isIntersecting && !hasFiredViewEvent.current) {
179→            firePromoTrendingRecommendationViewEvent({categoryName});
180→            hasFiredViewEvent.current = true;
181→          }
182→        });
183→      },
184→      {threshold: 0.1}
185→    );
186→
187→    observer.observe(boundingBoxRef.current);
188→
189→    return () => {
190→      observer.disconnect();
191→    };
192→  }, [categoryId, categoryName, products]);
193→
194→  const handleLeftClick = useCallback((e) => {
195→    e.stopPropagation();
196→    if (instanceRef?.current?.prev) {
197→      instanceRef.current.prev();
198→    }
199→  }, []);
200→
201→  const handleRightClick = useCallback((e) => {
202→    e.stopPropagation();
203→    if (instanceRef?.current?.next) {
204→      instanceRef.current.next();
205→    }
206→  }, []);
207→
208→  if (isLoading) {
209→    return (
210→      <Box data-testid="category-reco-trending-loading">
211→        <CarouselSkeleton />
212→      </Box>
213→    );
214→  }
215→
216→  if (products.length === 0) {
217→    return null;
218→  }
219→
220→  const showArrows = slidesPerView !== 'auto' && !isMobile;
221→
222→  const productCards = products.map((product) => (
223→    <RelatedProductCard
224→      key={`trending-carousel-${product.style_id}`}
225→      sx={{
226→        width: '100%',
227→        ...(isMobile && {
228→          '& .MuiCardContent-root': {
229→            display: 'flex',
230→            flex: '1 1 auto',
231→            flexDirection: 'column',
232→            gap: '0.25rem !important',
233→            minHeight: 'calc(100% - 13rem) !important',
234→            padding: '0.5rem !important'
235→          },
236→          '& .rpc-image-wrapper': {
237→            flexShrink: 0,
238→            height: '10.3125rem !important',
239→            paddingTop: '0 !important',
240→            width: '100% !important'
241→          },
242→          '& [data-testid="reco-product-name"]': {
243→            marginBottom: '0 !important',
244→            minHeight: '2rem',
245→            WebkitLineClamp: 2
246→          },
247→          height: '22rem'
248→        })
249→      }}
250→      onClick={() => {
251→        firePromoTrendingRecommendationClickEvent(product);
252→        if (onProductClick) {
253→          onProductClick(product);
254→        }
255→      }}
256→      linkHref={createRecoCardLinkHref({
257→        stylePath: product.link
258→      })}
259→      imageSrc={product.image_src}
260→      imageSrcSet={product.image_srcset || ''}
261→      minQty={product.min_qty}
262→      name={product.name}
263→      ratingCount={product.rating_count}
264→      ratingScore={product.rating_score}
265→      sizing={product.sizing}
266→      generalComments={product.general_comments || ''}
267→      defaultUnitPrices={product.default_unit_prices}
268→      primaryCategoryId={product.primary_category_id}
269→      styleType={product.style_type}
270→      defaultQuoteQty={product.default_quote_qty}
271→      productId={product.style_id}
272→      styleId={product.style_id}
273→      widgetType="trending"
274→      categories={
275→        product.categories || [
276→          {
277→            id: product.primary_category_id,
278→            name: product.primary_category_name
279→          }
280→        ]
281→      }
282→    />
283→  ));
284→
285→  return (
286→    <FavoritesProvider pageType={PageType.SUBCATEGORY}>
287→      <Container data-testid="category-reco-trending">
288→        <TrendingProductsHeader isMobile={isMobile}>
289→          <Typography
290→            data-testid="category-reco-trending-title"
291→            sx={{
292→              color: semantics.light.neutral.text.primary,
293→              fontSize: '1.5rem',
294→              fontWeight: 700,
295→              lineHeight: 1.25
296→            }}>
297→            {title}
298→          </Typography>
299→        </TrendingProductsHeader>
300→        <CarouselContainer>
301→          <SliderWrapper ref={boundingBoxRef}>
302→            {showArrows && (
303→              <div className="arrow-container">
304→                <IconButton
305→                  disableRipple
306→                  className={`arrow left ${isFirstSlide ? 'disabled' : ''}`}
307→                  data-testid="category-reco-trending-prev"
308→                  onClick={handleLeftClick}
309→                  disabled={isFirstSlide}
310→                  aria-label="Previous products">
311→                  <ArrowDownIcon
312→                    sx={{fill: semantics.light.neutral.icon.default}}
313→                    fontSize="inherit"
314→                  />
315→                </IconButton>
316→
317→                <IconButton
318→                  disableRipple
319→                  className={`arrow right ${isLastSlide ? 'disabled' : ''}`}
320→                  data-testid="category-reco-trending-next"
321→                  onClick={handleRightClick}
322→                  disabled={isLastSlide}
323→                  aria-label="Next products">
324→                  <ArrowDownIcon
325→                    sx={{fill: semantics.light.neutral.icon.default}}
326→                    fontSize="inherit"
327→                  />
328→                </IconButton>
329→              </div>
330→            )}
331→            <div
332→              ref={sliderRef}
333→              className="keen-slider"
334→              style={{paddingRight: '0'}}>
335→              {productCards.map((slide, i) => (
336→                <div
337→                  key={slide.key}
338→                  data-testid="category-reco-trending-slide"
339→                  className={`keen-slider__slide slide-${i} ${slidesPerView === 'auto' ? 'slide_auto_width' : ''}`}>
340→                  {slide}
341→                </div>
342→              ))}
343→            </div>
344→          </SliderWrapper>
345→        </CarouselContainer>
346→      </Container>
347→    </FavoritesProvider>
348→  );
349→};
