  1→// This file contains functions to push events to the data layer for Google Tag Manager (GTM) or other analytics tools.
  2→const pushToDataLayer = (object) => {
  3→  window.dataLayer.push(object);
  4→};
  5→
  6→const pushInteractionToDatalayer = ({
  7→  action,
  8→  category,
  9→  event,
 10→  eventCallback,
 11→  eventTimeout,
 12→  label,
 13→  value = undefined
 14→}) => {
 15→  const interaction = {
 16→    event,
 17→    interaction_action: action,
 18→    interaction_category: category,
 19→    interaction_label: label
 20→  };
 21→
 22→  if (value) {
 23→    interaction.interaction_value = value;
 24→  }
 25→
 26→  if (eventCallback) {
 27→    interaction.eventCallback = eventCallback;
 28→    interaction.eventTimeout = eventTimeout || 2000;
 29→  }
 30→
 31→  pushToDataLayer(interaction);
 32→};
