import React from 'react';
import useBreakpoint from 'hooks/useBreakpoint';
// @ts-ignore - no type declarations
import {TrendingBanner} from 'features/TrendingProducts';
// @ts-ignore - no type declarations
import promoImage from 'images/trending-banner/march-promo-desktop.png';
// @ts-ignore - no type declarations
import promoImageTablet from 'images/trending-banner/march-promo-tablet.png';
import {BANNER_TYPES} from 'utils/constants/bannerConstants';
import {
  fireMarchPromoInteractionGA4Event,
  fireMarchPromoRenderedGA4Event
} from 'utils/metrics/marchPromoBanner';

interface MarchPromoBannerProps {
  categoryId: number;
}

const MarchPromoBanner = ({categoryId}: MarchPromoBannerProps): JSX.Element => {
  const breakpoint = useBreakpoint();
  const isMobile = breakpoint === 'sm';

  return (
    <TrendingBanner
      categoryId={categoryId}
      backgroundColor={isMobile ? '#634A9F' : '#634A9F33'}
      bannerControlTag="march-promo-control"
      bannerImageDesktop={promoImage}
      bannerImageTablet={promoImageTablet}
      bannerTitle={isMobile ? '15% Off Office Supplies' : null}
      bannerSubtitle={
        isMobile ? 'Save on supplies, tech accessories, and awards.' : null
      }
      bannerType={BANNER_TYPES.MARCH_PROMO}
      fireGARenderedEvent={fireMarchPromoRenderedGA4Event}
      fireGAClickedEvent={fireMarchPromoInteractionGA4Event}
    />
  );
};

export default MarchPromoBanner;

