  },
  // TODO: No semantic token available for translucent white backgrounds
  backgroundColor: 'rgba(255, 255, 255, 0.8)',
  borderRadius: '0.5rem',
  display: 'flex',
  flexDirection: 'column',
  left: '50%',
  padding: '2rem',
  position: 'absolute',
  top: '50%',
  transform: 'translate(-50%, -50%)',
