import 'src/shared/gtm/types';

interface TrendingPromoProduct {
  style_id: string | number;
  name?: string;
  brand?: string[];
  primary_category_name?: string;
  style_type?: string;
}

interface EcommerceItem {
  index: number;
  item_id: string | number;
}

interface ViewEventParams {
  categoryName: string;
  categoryId?: string | number;
  items: EcommerceItem[];
}

interface ClickEventParams {
  product: TrendingPromoProduct;
  index: number;
  categoryId?: string | number;
  categoryName?: string;
}

const PAGE_TYPE = 'custom {{categoryName}} category';
const INTERACTION_CATEGORY = 'category_trending_products';

export const firePromoTrendingRecommendationViewEvent = ({
  categoryName,
  categoryId,
  items
}: ViewEventParams): void => {
  window.dataLayer?.push({ecommerce: null});
  window.dataLayer?.push({
    event: 'recommendation_view',
    page_type: PAGE_TYPE.replace('{{categoryName}}', categoryName),
    interaction_category: INTERACTION_CATEGORY,
    ecommerce: {
      item_list_id: categoryId,
      item_list_name: categoryName,
      items
    }
  });
};

export const firePromoTrendingRecommendationClickEvent = ({
  product,
  index,
  categoryId,
  categoryName
}: ClickEventParams): void => {
  window.dataLayer?.push({ecommerce: null});
  window.dataLayer?.push({
    event: 'recommendation_click',
    product_style_id: product.style_id,
    interaction_category: INTERACTION_CATEGORY,
    interaction_action: 'module click',
    interaction_label: 'regular',
    ecommerce: {
      item_list_id: categoryId,
      item_list_name: categoryName,
      items: [{index, item_id: product.style_id}]
    }
  });
};

