import 'keen-slider/keen-slider.min.css';
import {semantics} from '@customink/design-tokens';
import {
  ArrowDownIcon,
  Box,
  IconButton,
  Typography
} from '@customink/pigment-react';
import {styled} from '@mui/material/styles';
import FavoritesProvider, {
  PageType
} from 'features/favorites/FavoritesProvider';
import useResizeObserver from '@react-hook/resize-observer';
import KeenSlider from 'keen-slider';
import PropTypes from 'prop-types';
import React, {useCallback, useEffect, useMemo, useRef, useState} from 'react';
import useTrendingProductsWrapper from 'hooks/queries/useTrendingProductsWrapper';
import useBreakpoint from 'hooks/useBreakpoint';
import RelatedProductCard from 'product_details_page/RelatedProducts/RelatedProductCard';
import createRecoCardLinkHref from 'utils/createRecoCardLinkHref';
import config from '../../config';
import {BannerSkeleton} from './components/LoadingSkeleton';
import {BANNER_TYPES} from 'utils/constants/bannerConstants';
import useIntersectionObserverOnce from 'hooks/useIntersectionObserverOnce';

const BannerContainer = styled(Box)(() => ({
  '@media (max-width: 699px)': {
    margin: '0 !important',
    padding: '2rem 0'
  },
  '@media (max-width: 1023px)': {
    borderRadius: 0,
    flexDirection: 'column',
    height: 'auto',
    left: '50%',
    margin: '0 !important',
    position: 'relative',
    transform: 'translateX(-50%)',
    width: '100vw'
  },
  '@media (min-width: 1024px) and (max-width: 1299px)': {
    height: '27.50625rem'
  },
  backgroundColor: '#f1f4fe',
  borderRadius: '0.5rem',
  display: 'flex',
  height: '30.5625rem',
  marginBottom: '2.5rem',
  marginTop: '2.5rem',
  overflow: 'hidden',
  position: 'relative',
  width: '100%'
}));

const BannerImage = styled(Box)(({isMobile, isTablet}) => ({
  '@media (max-width: 699px)': {
    alignItems: 'center',
    display: 'flex',
    flexDirection: 'row-reverse'
  },
  '@media (max-width: 1023px)': {
    height: 'auto',
    width: '100%'
  },
  '@media (min-width: 1024px) and (max-width: 1299px)': {
    width: '29.98125rem'
  },
  ...(!isMobile &&
    !isTablet && {
      backgroundPosition: 'left center',
      backgroundRepeat: 'no-repeat',
      backgroundSize: 'cover'
    }),
  flexShrink: 0,
  height: '100%',
  position: 'relative',
  width: '35rem'
}));

const BannerImageText = styled(Box)(() => ({
  '@media (max-width: 699px)': {
    borderRadius: 0,
    left: 0,
    padding: '0 1rem',
    position: 'relative',
    top: 0,
    transform: 'unset',
    width: '100%'
  },
  // TODO: No semantic token available for translucent white backgrounds
  backgroundColor: 'rgba(255, 255, 255, 0.8)',
  borderRadius: '0.5rem',
  display: 'flex',
  flexDirection: 'column',
  left: '50%',
  padding: '2rem',
  position: 'absolute',
  top: '50%',
  transform: 'translate(-50%, -50%)',
  width: 'calc(100% - 7rem)'
}));

const BannerContent = styled(Box)(() => ({
  '@media (max-width: 699px)': {
    padding: '0 1rem',
    width: '100%'
  },
  '@media (min-width: 700px) and (max-width: 1023px)': {
    padding: '1.5rem 1rem 2rem',
    width: '100%'
  },
  '@media (min-width: 1024px) and (max-width: 1299px)': {
    width: 'calc(100% - 29.98125rem)'
  },
  display: 'flex',
  flex: 1,
  flexDirection: 'column',
  padding: '1.8rem 0 2.3rem 2rem',
  width: 'calc(100% - 35rem)'
}));

const BannerContentHeader = styled(Box)(() => ({
  '@media (max-width: 699px)': {
    padding: '0 0 1.5rem 0'
  },
  '@media (min-width: 700px) and (max-width: 1023px)': {
    marginBottom: '1.5rem',
    padding: '1rem 0'
  },
  alignItems: 'center',
  display: 'flex',
  justifyContent: 'space-between',
  padding: '1.8rem 0 2.5rem'
}));

const BannerContentButtons = styled(Box)(() => ({
  display: 'flex',
  gap: '0.5rem',
  marginRight: '1.5rem'
}));

const BannerContentBody = styled('div')(() => ({
  '.keen-slider': {
    '@media (max-width: 1023px)': {
      height: '17.9rem',
      overflow: 'visible !important'
    },
    display: 'flex !important',
    height: '19.6rem',
    overflow: 'hidden !important',
    position: 'relative',
    touchAction: 'pan-y',
    userSelect: 'none',
    WebkitTouchCallout: 'none'
  },
  '.keen-slider__slide': {
    '@media (max-width: 1023px)': {
      height: '17.9rem',
      minHeight: '17.9rem'
    },
    '@media (min-width: 1024px) and (max-width: 1299px)': {
      height: '18.5rem',
      minHeight: '18.5rem'
    },
    height: '19.6rem',
    minHeight: '19.6rem',
    overflow: 'hidden',
    position: 'relative'
  },
  '.slide_auto_width': {
    '@media (max-width: 1023px)': {
      marginRight: '1rem',
      maxWidth: '12.5rem'
    },
    '@media (min-width: 1024px) and (max-width: 1299px)': {
      marginRight: '1rem',
      maxWidth: '9.375rem'
    },
    marginRight: '2rem',
    maxWidth: '12.5rem',
    width: '100%'
  },
  '@media (max-width: 1023px)': {
    overflow: 'visible'
  },
  width: '100%'
}));

const TrendingBanner = ({
  backgroundColor = '#f1f4fe',
  bannerControlTag,
  bannerImageDesktop,
  bannerImageMobile,
  bannerImageTablet,
  bannerSubtitle,
  bannerTitle,
  bannerType = BANNER_TYPES.TRENDING,
  carouselTitle = 'Shop Trending Products',
  categoryId,
  onProductClick,
  fireGARenderedEvent,
  fireGAClickedEvent
}) => {
  const mainRef = useRef(null);
  const breakpoint = useBreakpoint();
  const isMobile = breakpoint === 'sm';
  const isTablet = breakpoint === 'md';
  const isSmallDesktop = breakpoint === 'lg';
  const {isLoading, products} = useTrendingProductsWrapper({
    bannerType,
    categoryId
  });

  const [isFirstSlide, setIsFirstSlide] = useState(true);
  const [isLastSlide, setIsLastSlide] = useState(false);

  const mappedItems = useMemo(
    () =>
      products.map((product, idx) => ({
        index: idx + 1,
        item_id: product.style_id
      })),
    [products]
  );

  useIntersectionObserverOnce(mainRef, () => {
    if (fireGARenderedEvent) {
      fireGARenderedEvent(mappedItems);
    }
  });

  const getSlidesPerView = () => {
    if (isMobile) {
      return products.length >= 3 ? 2.25 : 'auto';
    }
    if (isSmallDesktop) {
      return products.length >= 4 ? 2.5 : 'auto';
    }
    if (isTablet) {
      return products.length >= 4 ? 3.5 : 'auto';
    }
    return products.length >= 5 ? 3.5 : 'auto';
  };

  const slidesPerView = getSlidesPerView();

  const getGap = () => {
    if (isMobile) return 8;

    return 16;
  };
  const gap = getGap();

  const sliderRef = useRef(null);
  const instanceRef = useRef(null);

  useEffect(() => {
    if (sliderRef.current && products.length > 0) {
      instanceRef.current = new KeenSlider(sliderRef.current, {
        created: () => {
          setIsFirstSlide(false);
          setIsLastSlide(false);
        },
        initial: 0,
        loop: true,
        mode: 'free-snap',
        slideChanged: () => {
          setIsFirstSlide(false);
          setIsLastSlide(false);
        },
        slidesPerView,
        spacing: gap
      });
    }

    return () => {
      if (instanceRef.current) {
        instanceRef.current.destroy();
        instanceRef.current = null;
      }
    };
  }, [products.length, slidesPerView, gap, isMobile, isTablet, isSmallDesktop]);

  useEffect(() => {
    if (products.length > 0) {
      setIsFirstSlide(false);
      setIsLastSlide(false);
    }
  }, [products.length, slidesPerView, isMobile]);

  const boundingBoxRef = useRef(null);
  useResizeObserver(boundingBoxRef, () => instanceRef?.current?.refresh());

  const handleLeftClick = useCallback((e) => {
    e.stopPropagation();
    if (instanceRef?.current) {
      instanceRef.current.prev();
    }
  }, []);

  const handleRightClick = useCallback((e) => {
    e.stopPropagation();
    if (instanceRef?.current) {
      instanceRef.current.next();
    }
  }, []);

  const showArrows = slidesPerView !== 'auto' && !isMobile;

  const bannerImage = useMemo(() => {
    if (isMobile) return bannerImageMobile;
    if (isTablet) return bannerImageTablet;
    return bannerImageDesktop;
  }, [
    isMobile,
    isTablet,
    bannerImageMobile,
    bannerImageTablet,
    bannerImageDesktop
  ]);

  useEffect(() => {
    const controlTag = document.getElementById(bannerControlTag);
    if (controlTag) {
      if (!isLoading && products.length === 0) {
        controlTag.classList.add('hide');
      } else {
        controlTag.classList.remove('hide');
      }
    }
  }, [bannerControlTag, isLoading, products.length]);

  if (isLoading) {
    return <BannerSkeleton />;
  }

  const productCards = products.map((product, productIndex) => (
    <RelatedProductCard
      key={`trending-product-${product.style_id}`}
      sx={{
        width: '100%',
        '&:hover': {
          boxShadow: 'none'
        },
        '& .MuiCardContent-root': {
          display: 'flex',
          flex: '1 1 auto',
          flexDirection: 'column',
          gap: '0.5rem !important',
          minHeight: '7.5rem !important',
          padding: '0.75rem 0.5rem !important',
          fontFamily: 'SharpSans, sans-serif',
          '& > div:last-child': {
            display: 'none'
          },
          '@media (min-width: 768px)': {
            padding: '0.75rem 1rem !important'
          }
        },
        '& .rpc-image-wrapper': {
          flexShrink: 0,
          height: '9rem !important',
          paddingTop: '0 !important',
          width: '100% !important',
          '@media (min-width: 1300px)': {
            height: '10.3rem !important'
          }
        },
        '& [data-testid="reco-product-name"]': {
          fontFamily: 'SharpSans, sans-serif',
          marginBottom: '0 !important',
          minHeight: '2rem',
          WebkitLineClamp: 2
        },
        '& [data-testid="product-price-container"]': {
          fontFamily: 'SharpSans, sans-serif',
          marginBottom: '0.5rem',
          color: semantics.light.neutral.text.secondary
        },
        span: {
          fontFamily: 'SharpSans, sans-serif'
        },
        height: '17.9rem',
        '@media (min-width: 1024px) and (max-width: 1299px)': {
          height: '18.5rem'
        },
        '@media (min-width: 1300px)': {
          height: '19.6rem'
        }
      }}
      onClick={() => {
        if (fireGAClickedEvent) {
          fireGAClickedEvent(product, productIndex + 1);
        }
        if (onProductClick) {
          onProductClick(product);
        }
      }}
      linkHref={createRecoCardLinkHref({
        stylePath: product.link
      })}
      imageSrc={product.image_src}
      imageSrcSet={product.image_srcset || ''}
      minQty={product.min_qty}
      name={product.name}
      ratingCount={product.rating_count}
      ratingScore={product.rating_score}
      sizing={product.sizing}
      generalComments={product.general_comments || ''}
      defaultUnitPrices={product.default_unit_prices}
      primaryCategoryId={product.primary_category_id}
      styleType={product.style_type}
      defaultQuoteQty={product.default_quote_qty}
      productId={product.style_id}
      styleId={product.style_id}
      widgetType="promotion"
      categories={
        product.categories || [
          {
            id: product.primary_category_id,
            name: product.primary_category_name
          }
        ]
      }
      showFavoritesIcon={false}
    />
  ));

  if (products.length === 0) {
    return null;
  }

  return (
    <FavoritesProvider pageType={PageType.SUBCATEGORY}>
      <BannerContainer sx={{backgroundColor}} ref={mainRef}>
        <BannerImage
          isMobile={isMobile}
          isTablet={isTablet}
          sx={{
            backgroundColor,
            ...(!isMobile &&
              !isTablet &&
              bannerImageDesktop && {
                backgroundImage: `url(${config.assets.imagePath}${bannerImageDesktop})`
              })
          }}>
          {(isMobile || isTablet) && bannerImage ? (
            <img
              src={`${config.assets.imagePath}${bannerImage}`}
              alt={bannerTitle || 'Promotional Banner'}
              style={{
                display: 'block',
                height: 'auto',
                width: isMobile ? '30%' : '100%'
              }}
            />
          ) : null}
          {(bannerTitle || bannerSubtitle) && (
            <BannerImageText sx={{backgroundColor}}>
              {bannerTitle && (
                <Typography
                  sx={{
                    color: semantics.light.neutral.text.primaryOnFill,
                    fontSize: '1.75rem',
                    fontWeight: 800,
                    lineHeight: 1.1,
                    letterSpacing: '-0.035rem',
                    '@media (max-width: 699px)': {
                      fontSize: '1.5rem'
                    }
                  }}>
                  {bannerTitle}
                </Typography>
              )}
              {bannerSubtitle && (
                <Typography
                  sx={{
                    width: '18.5rem',
                    color: semantics.light.neutral.text.primaryOnFill,
                    fontSize: '0.75rem',
                    fontWeight: 700,
                    lineHeight: '1.25',
                    marginTop: '0.5rem'
                  }}>
                  {bannerSubtitle}
                </Typography>
              )}
              {bannerSubtitle && (
                <Typography
                  sx={{
                    width: '18.5rem',
                    color: semantics.light.neutral.text.primaryOnFill,
                    fontSize: '0.625rem',
                    fontWeight: 500,
                    lineHeight: '1.5',
                    marginTop: '0.5rem'
                  }}>
                  Act fast - deal ends Mar 30th. Prices as marked.*
                </Typography>
              )}
            </BannerImageText>
          )}
        </BannerImage>
        <BannerContent>
          <BannerContentHeader>
            {!isMobile && (
              <Typography
                sx={{
                  color: semantics.light.neutral.text.primary,
                  fontFamily: 'SharpSans, sans-serif',
                  fontSize: '1.5rem',
                  fontWeight: 700,
                  lineHeight: 1.25,
                  '@media (max-width: 1023px)': {
                    fontSize: '1.125rem'
                  }
                }}>
                {carouselTitle}
              </Typography>
            )}
            {showArrows && (
              <BannerContentButtons>
                <IconButton
                  onClick={handleLeftClick}
                  disabled={isFirstSlide}
                  disableRipple
                  sx={{
                    // TODO: No semantic token available for translucent white backgrounds with varying opacity
                    '&:disabled': {
                      backgroundColor: 'rgba(255, 255, 255, 0.3)',
                      boxShadow: 'none',
                      opacity: 0.5
                    },
                    '&:hover': {
                      backgroundColor: isFirstSlide
                        ? 'rgba(255, 255, 255, 0.6)'
                        : 'rgba(255, 255, 255, 0.8)'
                    },
                    backgroundColor: 'rgba(255, 255, 255, 0.6)',
                    borderRadius: '50%',
                    boxShadow: isFirstSlide
                      ? 'none'
                      : '0 0.25rem 0.5rem 0 rgba(0,0,0,0.08)',
                    height: '2rem',
                    minWidth: '2rem',
                    width: '2rem'
                  }}
                  aria-label="scroll left">
                  <ArrowDownIcon
                    sx={{
                      fill: isFirstSlide
                        ? semantics.light.interactive.icon.disabled
                        : semantics.light.neutral.icon.strong,
                      fontSize: '1.5rem',
                      transform: 'rotate(90deg)'
                    }}
                  />
                </IconButton>
                <IconButton
                  onClick={handleRightClick}
                  disabled={isLastSlide}
                  disableRipple
                  sx={{
                    // TODO: No semantic token available for translucent white backgrounds with varying opacity
                    '&:disabled': {
                      backgroundColor: 'rgba(255, 255, 255, 0.3)',
                      boxShadow: 'none',
                      opacity: 0.5
                    },
                    '&:hover': {
                      backgroundColor: isLastSlide
                        ? 'rgba(255, 255, 255, 0.6)'
                        : 'rgba(255, 255, 255, 0.8)'
                    },
                    backgroundColor: 'rgba(255, 255, 255, 0.6)',
                    borderRadius: '50%',
                    boxShadow: isLastSlide
                      ? 'none'
                      : '0 0.25rem 0.5rem 0 rgba(0,0,0,0.08)',
                    height: '2rem',
                    minWidth: '2rem',
                    width: '2rem'
                  }}
                  aria-label="scroll right">
                  <ArrowDownIcon
                    sx={{
                      fill: isLastSlide
                        ? semantics.light.interactive.icon.disabled
                        : semantics.light.neutral.icon.strong,
                      fontSize: '1.5rem',
                      transform: 'rotate(-90deg)'
                    }}
                  />
                </IconButton>
              </BannerContentButtons>
            )}
          </BannerContentHeader>
          <BannerContentBody ref={boundingBoxRef}>
            <div
              ref={sliderRef}
              className="keen-slider"
              style={{paddingRight: '0'}}>
              {productCards.map((slide, i) => (
                <div
                  key={slide.key}
                  className={`keen-slider__slide slide-${i} ${slidesPerView === 'auto' ? 'slide_auto_width' : ''}`}>
                  {slide}
                </div>
              ))}
            </div>
          </BannerContentBody>
        </BannerContent>
      </BannerContainer>
    </FavoritesProvider>
  );
};

TrendingBanner.propTypes = {
  backgroundColor: PropTypes.string,
  bannerImageDesktop: PropTypes.string,
  bannerImageMobile: PropTypes.string,
  bannerImageTablet: PropTypes.string,
  bannerSubtitle: PropTypes.string,
  bannerTitle: PropTypes.string,
  bannerType: PropTypes.oneOf(Object.values(BANNER_TYPES)),
  carouselTitle: PropTypes.string,
  categoryId: PropTypes.number.isRequired,
  onProductClick: PropTypes.func,
  fireGARenderedEvent: PropTypes.func,
  fireGAClickedEvent: PropTypes.func
};

export default TrendingBanner;

